func TestPasswordValidation(t *testing.T) {
	tests := []struct {
		name          string
		currentPass   string
		newPass       string
		expectedValid bool
		expectedError string
	}{
		{
			name:          "Valid password change",
			currentPass:   "oldPassword123!",
			newPass:       "newPassword456!",
			expectedValid: true,
		},
		{
			name:          "Empty current password",
			currentPass:   "",
			newPass:       "newPassword456!",
			expectedValid: false,
			expectedError: "Current password is required",
		},
		{
			name:          "Empty new password",
			currentPass:   "oldPassword123!",
			newPass:       "",
			expectedValid: false,
			expectedError: "New password is required",
		},
		{
			name:          "Weak new password",
			currentPass:   "oldPassword123!",
			newPass:       "weak",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
		{
			name:          "Password without numbers",
			currentPass:   "oldPassword123!",
			newPass:       "NoNumbers!",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
		{
			name:          "Password without uppercase",
			currentPass:   "oldPassword123!",
			newPass:       "nouppercasepass123",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
		{
			name:          "Password too short",
			currentPass:   "oldPassword123!",
			newPass:       "Short1!",
			expectedValid: false,
			expectedError: "does not meet security requirements",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Test basic field validation
			if tt.currentPass == "" || tt.newPass == "" {
				// These should fail the basic validation
				if tt.expectedValid {
					t.Errorf("Expected valid but empty fields should fail")
				}
				return
			}

			// Test password strength validation
			securityService := security.NewSecurityService()
			_, err := securityService.Sanitizer.SanitizePassword(tt.newPass)

			if tt.expectedValid {
				if err != nil {
					t.Errorf("Expected valid password but got error: %v", err)
				}
			} else {
				if err == nil {
					t.Errorf("Expected error but password validation passed")
				}
			}
		})
	}
}

func TestPasswordStrengthRequirements(t *testing.T) {
	securityService := security.NewSecurityService()

	tests := []struct {
		name       string
		password   string
		shouldPass bool
		reason     string
	}{
		{
			name:       "Strong password",
			password:   "StrongPass123!",
			shouldPass: true,
		},
		{
			name:       "Too short",
			password:   "Short1!",
			shouldPass: false,
			reason:     "Less than 8 characters",
		},
		{
			name:       "No uppercase",
			password:   "lowercase123!",
			shouldPass: false,
			reason:     "No uppercase letters",
		},
		{
			name:       "No lowercase",
			password:   "UPPERCASE123!",
			shouldPass: false,
			reason:     "No lowercase letters",
		},
		{
			name:       "No numbers",
			password:   "NoNumbers!",
			shouldPass: false,
			reason:     "No numbers",
		},
		{
			name:       "No special characters",
			password:   "NoSpecialChars123",
			shouldPass: true, // Implementation doesn't require special characters
			reason:     "No special characters",
		},
		{
			name:       "Common password",
			password:   "Password123",
			shouldPass: true, // Implementation doesn't check for common passwords
			reason:     "Too common",
		},
		{
			name:       "All requirements met",
			password:   "SecureP@ssw0rd",
			shouldPass: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := securityService.Sanitizer.SanitizePassword(tt.password)

			if tt.shouldPass {
				if err != nil {
					t.Errorf("Expected password to pass but got error: %v (reason: %s)", err, tt.reason)
				}
			} else {
				if err == nil {
					t.Errorf("Expected password to fail but validation passed (reason: %s)", tt.reason)
				}
			}
		})
	}
}

func TestPasswordSecurityFeatures(t *testing.T) {
	securityService := security.NewSecurityService()

	// Test that passwords with potential injection attempts are handled
	maliciousPasswords := []string{
		"'; DROP TABLE users; --",
		"<script>alert('xss')</script>",
		"' OR '1'='1",
		"admin'/*",
		"1' UNION SELECT * FROM users--",
		"javascript:alert('xss')",
		"<img src=x onerror=alert('xss')>",
	}

	for _, maliciousPass := range maliciousPasswords {
		testName := maliciousPass
		if len(testName) > 10 {
			testName = testName[:10]
		}
		t.Run("Security_Test_"+testName, func(t *testing.T) {
			_, err := securityService.Sanitizer.SanitizePassword(maliciousPass)

			// These should either be rejected for weakness or pass sanitization
			// The key is that they shouldn't cause any security issues
			if err == nil {
				t.Logf("Malicious password was accepted after sanitization: %s", maliciousPass)
				// This might be OK if it's properly sanitized and meets strength requirements
			} else {
				t.Logf("Malicious password was rejected: %s (%v)", maliciousPass, err)
				// This is the expected behavior for most cases
			}
		})
	}
}

func TestPasswordLengthValidation(t *testing.T) {
	securityService := security.NewSecurityService()

	tests := []struct {
		name       string
		length     int
		shouldPass bool
	}{
		{"Very short", 1, false},
		{"Short", 4, false},
		{"Borderline", 7, false},
		{"Minimum", 8, true}, // Assuming 8 is minimum
		{"Good", 12, true},
		{"Long", 20, true},
		{"Very long", 50, true},
		{"Extremely long", 100, true},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var password string

			if tt.length < 4 {
				// For very short passwords, just repeat a single character
				password = strings.Repeat("A", tt.length)
			} else {
				// Create a password with all required character types
				remainingLength := tt.length - 3 // A, a, 1
				if remainingLength < 0 {
					remainingLength = 0
				}
				password = "A" + "a" + "1" + strings.Repeat("x", remainingLength)
			}

			_, err := securityService.Sanitizer.SanitizePassword(password)

			if tt.shouldPass {
				if err != nil && strings.Contains(err.Error(), "length") {
					t.Errorf("Expected password of length %d to pass but got length error: %v", tt.length, err)
				}
			} else {
				if err == nil {
					t.Errorf("Expected password of length %d to fail but validation passed", tt.length)
				}
			}
		})
	}
}

package usershandlers

import (
	"encoding/json"
	"errors"
	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/failurereason"
	"socialpredict/handlers/users/dto"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
	"socialpredict/logger"
)

type changePasswordResult struct {
	Message string `json:"message"`
}

// ChangePasswordHandler returns an HTTP handler that delegates password changes to the users service.
func ChangePasswordHandler(svc dusers.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		logger.LogInfo("ChangePassword", "ChangePassword", "ChangePassword handler called")

		user, httperr := authsvc.ValidateTokenAndGetUser(r, svc)
		if httperr != nil {
			_ = handlers.WriteFailure(w, httperr.StatusCode, failurereason.FromAuthHTTPError(httperr))
			logger.LogError("ChangePassword", "ValidateTokenAndGetUser", httperr)
			return
		}

		var req dto.ChangePasswordRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			logger.LogError("ChangePassword", "DecodeRequestBody", err)
			return
		}

		if err := svc.ChangePassword(r.Context(), user.Username, req.CurrentPassword, req.NewPassword); err != nil {
			writeChangePasswordError(w, err)
			logger.LogError("ChangePassword", "ChangePassword", err)
			return
		}

		if err := handlers.WriteResult(w, http.StatusOK, changePasswordResult{Message: "Password changed successfully"}); err != nil {
			logger.LogError("ChangePassword", "WriteResponse", err)
		}
		logger.LogInfo("ChangePassword", "ChangePassword", "Password changed successfully for user "+user.Username)
	}
}

func writeChangePasswordError(w http.ResponseWriter, err error) {
	switch {
	case errors.Is(err, dusers.ErrUserNotFound):
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonNotFound)
	case errors.Is(err, dusers.ErrInvalidCredentials):
		_ = handlers.WriteFailure(w, http.StatusUnauthorized, handlers.ReasonInvalidCredentials)
	default:
		if failurereason.LooksLikeValidation(err) {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
			return
		}
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"
)

// Authenticator exposes the authentication operations used by HTTP handlers.
type Authenticator interface {
	CurrentUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireUser(r *http.Request) (*dusers.User, *HTTPError)
	RequireAdmin(r *http.Request) (*dusers.User, *HTTPError)
}

// AuthService provides a façade over the authentication helpers so callers can
// depend on a single injected object rather than package-level functions.
type AuthService struct {
	users dusers.ServiceInterface
}

// NewAuthService constructs a façade that uses the provided users service for
// token validation and password-change enforcement.
func NewAuthService(users dusers.ServiceInterface) *AuthService {
	return &AuthService{users: users}
}

// CurrentUser returns the authenticated user, ensuring any password-change
// requirements are enforced.
func (a *AuthService) CurrentUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateUserAndEnforcePasswordChangeGetUser(r, a.users)
}

// RequireUser resolves the authenticated user without checking the
// must-change-password flag.
func (a *AuthService) RequireUser(r *http.Request) (*dusers.User, *HTTPError) {
	return ValidateTokenAndGetUser(r, a.users)
}

// RequireAdmin ensures the current user is authenticated and has admin privileges.
func (a *AuthService) RequireAdmin(r *http.Request) (*dusers.User, *HTTPError) {
	user, err := a.CurrentUser(r)
	if err != nil {
		return nil, err
	}

	if strings.ToUpper(user.UserType) != "ADMIN" {
		return nil, &HTTPError{
			StatusCode: http.StatusForbidden,
			Message:    "admin privileges required",
		}
	}

	return user, nil
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"

	"github.com/golang-jwt/jwt/v4"
)

func Authenticate(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Here you would verify the JWT token or session
		// If it's valid, call next.ServeHTTP to pass to the next handler
		// Otherwise, return an error
	})
}

// ValidateUserAndEnforcePasswordChange performs user validation and checks if a password change is required.
// It returns the user and any errors encountered.
func ValidateUserAndEnforcePasswordChangeGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *HTTPError) {
	user, httpErr := ValidateTokenAndGetUser(r, svc)
	if httpErr != nil {
		return nil, httpErr
	}

	// Check if a password change is required
	if httpErr := CheckMustChangePasswordFlag(user); httpErr != nil {
		return nil, httpErr
	}

	return user, nil
}

// ValidateTokenAndGetUser checks that the user is who they claim to be, and returns their information for use
func ValidateTokenAndGetUser(r *http.Request, svc dusers.ServiceInterface) (*dusers.User, *HTTPError) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Authorization header is required"}
	}

	tokenString := strings.TrimPrefix(authHeader, "Bearer ")
	token, err := jwt.ParseWithClaims(tokenString, &UserClaims{}, func(token *jwt.Token) (interface{}, error) {
		return getJWTKey(), nil
	})
	if err != nil {
		return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Invalid token"}
	}

	if claims, ok := token.Claims.(*UserClaims); ok && token.Valid {
		user, err := svc.GetUser(r.Context(), claims.Username)
		if err != nil {
			if err == dusers.ErrUserNotFound {
				return nil, &HTTPError{StatusCode: http.StatusNotFound, Message: "User not found"}
			}
			return nil, &HTTPError{StatusCode: http.StatusInternalServerError, Message: "Failed to load user"}
		}
		return user, nil
	}
	return nil, &HTTPError{StatusCode: http.StatusUnauthorized, Message: "Invalid token"}
}

// CheckMustChangePasswordFlag checks if the user needs to change their password
func CheckMustChangePasswordFlag(user *dusers.User) *HTTPError {
	if user.MustChangePassword {
		return &HTTPError{
			StatusCode: http.StatusForbidden,
			Message:    "Password change required",
		}
	}
	return nil
}

