package handlers

import (
	"encoding/json"
	"net/http"
)

type FailureReason string

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}

	}
}

func TestUsernameLengthValidation(t *testing.T) {
	securityService := security.NewSecurityService()

	lengthTests := []struct {
		name       string
		length     int
		shouldPass bool
	}{
		{"Empty", 0, false},
		{"Single character", 1, false}, // Minimum is 3 characters
		{"Two characters", 2, false},
		{"Minimum valid", 3, true},
		{"Medium", 10, true},
		{"Maximum valid", 30, true},
		{"Over limit", 31, false},
		{"Way over limit", 100, false},
	}

	for _, test := range lengthTests {
		t.Run(test.name, func(t *testing.T) {
			var username string
			if test.length == 0 {
				username = ""
			} else {
				username = strings.Repeat("a", test.length)
			}

			testStruct := struct {
				Username string `validate:"required,min=3,max=30,username"`
			}{
				Username: username,
			}

			err := securityService.Validator.ValidateStruct(testStruct)

			if test.shouldPass {
				if err != nil {
					t.Errorf("Expected username length %d to be valid but got error: %v", test.length, err)
				}
			} else {
				if err == nil {
					t.Errorf("Expected username length %d to be invalid but validation passed", test.length)
				}
			}
		})
	}
}

